INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.1', 'knowledge', '{"content":"<b>Recap</b><br>• The <b>Cartesian plane</b> has a horizontal $x$-axis and vertical $y$-axis, crossing at the <b>origin</b> $(0, 0)$.<br>• A point is written as $(x, y)$. The $x$-coordinate comes first.<br>• <b>Four quadrants</b>: Q1 $(+, +)$, Q2 $(-, +)$, Q3 $(-, -)$, Q4 $(+, -)$.<br><br><b>Key Skills</b><br>• Plot and read coordinates in all four quadrants.<br>• Identify coordinates from geometric shapes drawn on axes.","content_zh":"<b>知识回顾</b><br>• <b>笛卡尔坐标系</b>有一个水平的 $x$ 轴和一个垂直的 $y$ 轴，它们在<b>原点</b> $(0, 0)$ 相交。<br>• 点记作 $(x, y)$。$x$ 坐标排在第一位。<br>• <b>四个象限</b>：Q1 $(+, +)$，Q2 $(-, +)$，Q3 $(-, -)$，Q4 $(+, -)$。<br><br><b>关键技能</b><br>• 在所有四个象限中绘制和读取坐标。<br>• 从坐标轴上绘制的几何图形中识别坐标。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>A rectangle has vertices at $A(1, 2)$, $B(5, 2)$, $C(5, 6)$. Find $D$.<br><br><b>Solution:</b><br>$D$ must complete the rectangle: same $x$ as $A$, same $y$ as $C$.<br>$D = (1, 6)$<br><br><b>Worked Example 2</b> [2 marks]<br>Write down the coordinates of the point $P$ that is 3 units to the left and 5 units above the origin.<br><br><b>Solution:</b><br>Left means negative $x$, above means positive $y$.<br>$P = (-3, 5)$<br><br><b>Worked Example 3</b> [3 marks]<br>A triangle has vertices $A(-2, -1)$, $B(4, -1)$, $C(1, 5)$. State which quadrant each vertex lies in.<br><br><b>Solution:</b><br>$A(-2, -1)$: $x < 0, y < 0$ → Quadrant 3 (Q3)<br>$B(4, -1)$: $x > 0, y < 0$ → Quadrant 4 (Q4)<br>$C(1, 5)$: $x > 0, y > 0$ → Quadrant 1 (Q1)<br><br><b>Worked Example 4</b> [3 marks]<br>A parallelogram $ABCD$ has $A(0, 0)$, $B(4, 0)$ and $D(1, 3)$. Find $C$.<br><br><b>Solution:</b><br>In a parallelogram, $\\vec{AB} = \\vec{DC}$.<br>$\\vec{AB} = (4, 0)$, so $C = D + (4, 0) = (1+4, 3+0) = (5, 3)$<br><br><b>Exam Tip:</b> In parallelogram problems, use the fact that opposite sides are equal and parallel to find missing vertices.","content_zh":"<b>经典例题 1</b> [2 分]<br>一个长方形的顶点位于 $A(1, 2)$，$B(5, 2)$，$C(5, 6)$。求 $D$ 的坐标。<br><br><b>解答：</b><br>$D$ 必须完善该长方形：其 $x$ 坐标与 $A$ 相同，$y$ 坐标与 $C$ 相同。<br>$D = (1, 6)$<br><br><b>经典例题 2</b> [2 分]<br>写出位于原点左边 3 个单位、上方 5 个单位的点 $P$ 的坐标。<br><br><b>解答：</b><br>左边表示 $x$ 为负，上方表示 $y$ 为正。<br>$P = (-3, 5)$<br><br><b>经典例题 3</b> [3 分]<br>一个三角形的顶点为 $A(-2, -1)$，$B(4, -1)$，$C(1, 5)$。指出每个顶点所在的象限。<br><br><b>解答：</b><br>$A(-2, -1)$：$x < 0, y < 0$ → 第三象限 (Q3)<br>$B(4, -1)$：$x > 0, y < 0$ → 第四象限 (Q4)<br>$C(1, 5)$：$x > 0, y > 0$ → 第一象限 (Q1)<br><br><b>经典例题 4</b> [3 分]<br>平行四边形 $ABCD$ 的顶点 $A(0, 0)$，$B(4, 0)$，$D(1, 3)$。求 $C$ 的坐标。<br><br><b>解答：</b><br>在平行四边形中，$\\vec{AB} = \\vec{DC}$。<br>$\\vec{AB} = (4, 0)$，所以 $C = D + (4, 0) = (5, 3)$<br><br><b>考试技巧：</b>在平行四边形问题中，利用对边相等且平行的性质来求缺失的顶点。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.2', 'knowledge', '{"content":"<b>Recap</b><br>• A linear graph is a straight line. Equation: $y = mx + c$.<br>• To draw: make a table of at least 3 values of $(x, y)$, plot, and join with a ruler.<br>• Special lines: $y = c$ is horizontal; $x = a$ is vertical.<br><br><b>Key Skills</b><br>• Draw lines from equations. Read equations from graphs.<br>• Find where two lines intersect (solve simultaneously).<br><br><b>Exam Tip</b><br>Use 3 points to draw a line — the third point checks for errors.","content_zh":"<b>知识回顾</b><br>• 线性图是一条直线。方程为：$y = mx + c$。<br>• 绘制方法：列出至少 3 组 $(x, y)$ 值的表格，描点，并用直尺连接。<br>• 特殊直线：$y = c$ 是水平线；$x = a$ 是垂直线。<br><br><b>关键技能</b><br>• 根据方程画线。从图表中读取方程。<br>• 找到两条直线的交点（联立求解）。<br><br><b>考试技巧</b><br>使用 3 个点来画线 —— 第三个点用于检查错误。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.2', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Draw the graph of $y = 2x - 3$ for $-1 \\leq x \\leq 4$.<br><br><b>Solution:</b><br>$x = -1$: $y = -5$; $x = 0$: $y = -3$; $x = 2$: $y = 1$; $x = 4$: $y = 5$.<br>Plot these points and join with a straight line.<br><br><b>Worked Example 2</b> [2 marks]<br>On the same axes, draw the lines $y = 4$ and $x = -2$.<br><br><b>Solution:</b><br>$y = 4$ is a horizontal line through $(0, 4)$.<br>$x = -2$ is a vertical line through $(-2, 0)$.<br>The two lines intersect at $(-2, 4)$.<br><br><b>Worked Example 3</b> [3 marks]<br>A straight line passes through $(0, -1)$ and $(3, 5)$. Find its equation in the form $y = mx + c$.<br><br><b>Solution:</b><br>$y$-intercept $c = -1$ (the line crosses the $y$-axis at $(0, -1)$).<br>$m = \\frac{5 - (-1)}{3 - 0} = \\frac{6}{3} = 2$<br>$y = 2x - 1$<br><br><b>Worked Example 4</b> [3 marks]<br>Use the graph of $y = 3x + 1$ and $y = -x + 9$ to find their point of intersection.<br><br><b>Solution:</b><br>At the intersection, $3x + 1 = -x + 9$.<br>$4x = 8$, so $x = 2$.<br>$y = 3(2) + 1 = 7$. Intersection at $(2, 7)$.<br><br><b>Exam Tip:</b> Always use a ruler for straight-line graphs. Use at least 3 points — the third checks for errors.","content_zh":"<b>经典例题 1</b> [3 分]<br>画 $y = 2x - 3$ 在 $-1 \\leq x \\leq 4$ 的图像。<br><br><b>解答：</b>代入 $x = -1, 0, 2, 4$ 得 $y = -5, -3, 1, 5$，描点用直尺连线。<br><br><b>经典例题 2</b> [2 分]<br>在同一坐标系上画出 $y = 4$ 和 $x = -2$。<br><br><b>解答：</b><br>$y = 4$ 是过 $(0, 4)$ 的水平线。<br>$x = -2$ 是过 $(-2, 0)$ 的垂直线。<br>两线交于 $(-2, 4)$。<br><br><b>经典例题 3</b> [3 分]<br>一条直线过 $(0, -1)$ 和 $(3, 5)$。求其方程（$y = mx + c$ 形式）。<br><br><b>解答：</b><br>$y$ 轴截距 $c = -1$。<br>$m = \\frac{5-(-1)}{3-0} = 2$<br>$y = 2x - 1$<br><br><b>经典例题 4</b> [3 分]<br>利用 $y = 3x + 1$ 和 $y = -x + 9$ 的图像求其交点。<br><br><b>解答：</b><br>交点处 $3x + 1 = -x + 9$，$4x = 8$，$x = 2$，$y = 7$。交于 $(2, 7)$。<br><br><b>考试技巧：</b>画直线时一定用直尺。用至少 3 个点描图——第三个点用来验证。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Gradient</b> (slope) = $\\frac{\\text{rise}}{\\text{run}} = \\frac{y_2 - y_1}{x_2 - x_1}$.<br>• Positive gradient: line goes uphill (left to right).<br>• Negative gradient: line goes downhill.<br>• Zero gradient: horizontal line. Undefined gradient: vertical line.<br>• In $y = mx + c$, $m$ is the gradient.<br><br><b>Key Skills</b><br>• Calculate gradient from two points.<br>• Read gradient from a graph using a right-angled triangle.<br><br><b>Exam Tip</b><br>Pick two points far apart on the line for a more accurate gradient calculation.","content_zh":"<b>知识回顾</b><br>• <b>斜率（Gradient/slope）</b> = $\\frac{\\text{上升}}{\\text{水平距离}} = \\frac{y_2 - y_1}{x_2 - x_1}$。<br>• 正斜率：直线向上倾斜（从左到右）。<br>• 负斜率：直线向下倾斜。<br>• 零斜率：水平线。未定义斜率：垂直线。<br>• 在 $y = mx + c$ 中，$m$ 是斜率。<br><br><b>关键技能</b><br>• 根据两点计算斜率。<br>• 使用直角三角形从图表中读取斜率。<br><br><b>考试技巧</b><br>在直线上选取两个相距较远的点，以获得更准确的斜率计算结果。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.3', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Find the gradient of the line through $(2, 5)$ and $(8, -1)$.<br><br><b>Solution:</b><br>$m = \\frac{-1 - 5}{8 - 2} = \\frac{-6}{6} = -1$<br><br><b>Worked Example 2</b> [2 marks]<br>A line passes through $(-3, 4)$ and $(5, 4)$. Find its gradient.<br><br><b>Solution:</b><br>$m = \\frac{4 - 4}{5 - (-3)} = \\frac{0}{8} = 0$<br>The gradient is 0 — the line is horizontal.<br><br><b>Worked Example 3</b> [3 marks]<br>The line $y = mx + 5$ passes through $(4, -3)$. Find $m$.<br><br><b>Solution:</b><br>Substitute the point: $-3 = m(4) + 5$<br>$4m = -8$<br>$m = -2$<br><br><b>Worked Example 4</b> [3 marks]<br>A line has gradient $\\frac{3}{4}$. The line passes through $(0, 2)$ and $(8, k)$. Find $k$.<br><br><b>Solution:</b><br>$\\frac{3}{4} = \\frac{k - 2}{8 - 0}$<br>$k - 2 = \\frac{3}{4} \\times 8 = 6$<br>$k = 8$<br><br><b>Exam Tip:</b> Be consistent: always subtract in the same order for both numerator and denominator.","content_zh":"<b>经典例题 1</b> [2 分]<br>求通过 $(2, 5)$ 和 $(8, -1)$ 的直线的斜率。<br><br><b>解答：</b><br>$m = \\frac{-1 - 5}{8 - 2} = \\frac{-6}{6} = -1$<br><br><b>经典例题 2</b> [2 分]<br>一条直线通过 $(-3, 4)$ 和 $(5, 4)$。求其斜率。<br><br><b>解答：</b><br>$m = \\frac{4-4}{5-(-3)} = \\frac{0}{8} = 0$<br>斜率为 0——这是一条水平线。<br><br><b>经典例题 3</b> [3 分]<br>直线 $y = mx + 5$ 通过点 $(4, -3)$。求 $m$。<br><br><b>解答：</b><br>代入点：$-3 = 4m + 5$，$4m = -8$，$m = -2$<br><br><b>经典例题 4</b> [3 分]<br>一条直线的斜率为 $\\frac{3}{4}$，通过 $(0, 2)$ 和 $(8, k)$。求 $k$。<br><br><b>解答：</b><br>$\\frac{3}{4} = \\frac{k-2}{8}$，$k - 2 = 6$，$k = 8$<br><br><b>考试技巧：</b>分子和分母的减法顺序必须保持一致。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.4', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Distance</b> between $(x_1, y_1)$ and $(x_2, y_2)$:<br>$d = \\sqrt{(x_2 - x_1)^2 + (y_2 - y_1)^2}$ (Pythagoras on the coordinate plane).<br>• <b>Midpoint</b>: $M = \\left(\\frac{x_1 + x_2}{2}, \\frac{y_1 + y_2}{2}\\right)$.<br><br><b>Key Skills</b><br>• Calculate the exact distance between two points.<br>• Find the midpoint of a line segment.<br><br><b>Exam Tip</b><br>Leave answers in surd form if the question says \"exact value\".","content_zh":"<b>知识回顾</b><br>• $(x_1, y_1)$ 和 $(x_2, y_2)$ 之间的<b>距离</b>：<br>$d = \\sqrt{(x_2 - x_1)^2 + (y_2 - y_1)^2}$（坐标平面上的勾股定理）。<br>• <b>中点</b>：$M = \\left(\\frac{x_1 + x_2}{2}, \\frac{y_1 + y_2}{2}\\right)$。<br><br><b>关键技能</b><br>• 计算两点之间的精确距离。<br>• 求线段的中点。<br><br><b>考试技巧</b><br>如果题目要求\"精确值 (exact value)\"，请以根式形式保留答案。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.4', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Find the distance and midpoint of $A(1, 3)$ and $B(7, 11)$.<br><br><b>Solution:</b><br>$d = \\sqrt{(7-1)^2 + (11-3)^2} = \\sqrt{36 + 64} = \\sqrt{100} = 10$<br>$M = \\left(\\frac{1+7}{2}, \\frac{3+11}{2}\\right) = (4, 7)$<br><br><b>Worked Example 2</b> [3 marks]<br>Find the exact distance between $P(-3, 2)$ and $Q(1, -1)$.<br><br><b>Solution:</b><br>$d = \\sqrt{(1-(-3))^2 + (-1-2)^2} = \\sqrt{16 + 9} = \\sqrt{25} = 5$<br><br><b>Worked Example 3</b> [3 marks — Extended]<br>The midpoint of $A(2, k)$ and $B(8, 10)$ is $M(5, 7)$. Find $k$.<br><br><b>Solution:</b><br>$\\frac{2 + 8}{2} = 5$ ✓ (confirms $x$-coordinate)<br>$\\frac{k + 10}{2} = 7$<br>$k + 10 = 14$<br>$k = 4$<br><br><b>Worked Example 4</b> [4 marks — Extended]<br>$A(1, 2)$ and $B(5, 8)$. Point $C$ is such that $B$ is the midpoint of $AC$. Find $C$.<br><br><b>Solution:</b><br>Let $C = (a, b)$. Since $B$ is the midpoint of $AC$:<br>$\\frac{1 + a}{2} = 5 \\Rightarrow a = 9$<br>$\\frac{2 + b}{2} = 8 \\Rightarrow b = 14$<br>$C = (9, 14)$<br><br><b>Exam Tip:</b> Leave answers in surd form if the question says \"exact value\". If finding a missing coordinate from a midpoint, set up equations and solve.","content_zh":"<b>经典例题 1</b> [3 分]<br>求 $A(1,3)$ 和 $B(7,11)$ 的距离和中点。<br><br><b>解答：</b><br>$d = \\sqrt{(7-1)^2 + (11-3)^2} = \\sqrt{36+64} = 10$<br>$M = (4, 7)$<br><br><b>经典例题 2</b> [3 分]<br>求 $P(-3, 2)$ 和 $Q(1, -1)$ 之间的精确距离。<br><br><b>解答：</b><br>$d = \\sqrt{16 + 9} = \\sqrt{25} = 5$<br><br><b>经典例题 3</b> [3 分 — 进阶]<br>$A(2, k)$ 和 $B(8, 10)$ 的中点是 $M(5, 7)$。求 $k$。<br><br><b>解答：</b><br>$\\frac{k + 10}{2} = 7$，$k + 10 = 14$，$k = 4$<br><br><b>经典例题 4</b> [4 分 — 进阶]<br>$A(1, 2)$ 和 $B(5, 8)$，$B$ 是 $AC$ 的中点。求 $C$。<br><br><b>解答：</b><br>设 $C = (a, b)$。$\\frac{1+a}{2} = 5$，$a = 9$；$\\frac{2+b}{2} = 8$，$b = 14$。<br>$C = (9, 14)$<br><br><b>考试技巧：</b>题目要求\"精确值\"时，答案保留根式形式。根据中点求坐标时，列等式求解。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.5', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Slope-intercept form</b>: $y = mx + c$ (gradient $m$, $y$-intercept $c$).<br>• Given gradient and a point: $y - y_1 = m(x - x_1)$.<br>• Given two points: find $m$ first, then use point-slope form.<br><br><b>Key Skills</b><br>• Write the equation of a line from a graph.<br>• Write the equation from gradient + point, or two points.<br>• Rearrange between $y = mx + c$ and $ax + by = c$.<br><br><b>Exam Tip</b><br>If given a graph, read off the $y$-intercept and calculate the gradient to write $y = mx + c$.","content_zh":"<b>知识回顾</b><br>• <b>斜截式</b>：$y = mx + c$（斜率 $m$，$y$ 轴截距 $c$）。<br>• 已知斜率和一个点：$y - y_1 = m(x - x_1)$。<br>• 已知两点：先求出 $m$，然后使用点斜式。<br><br><b>关键技能</b><br>• 根据图像写出直线方程。<br>• 根据斜率 + 一个点，或两点写出方程。<br>• 在 $y = mx + c$ 和 $ax + by = c$ 之间进行转换。<br><br><b>考试技巧</b><br>如果给出图像，读取 $y$ 轴截距并计算斜率以写出 $y = mx + c$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.5', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Find the equation of the line through $(2, 1)$ and $(6, 9)$.<br><br><b>Solution:</b><br>$m = \\frac{9-1}{6-2} = \\frac{8}{4} = 2$<br>$y - 1 = 2(x - 2)$<br>$y = 2x - 3$<br><br><b>Worked Example 2</b> [2 marks]<br>A line has gradient $-3$ and passes through $(0, 7)$. Write its equation.<br><br><b>Solution:</b><br>Since the line passes through $(0, 7)$, the $y$-intercept $c = 7$.<br>$y = -3x + 7$<br><br><b>Worked Example 3</b> [3 marks — Extended]<br>Find the equation of the line with gradient $\\frac{1}{2}$ that passes through $(6, -1)$. Give your answer in the form $ax + by = c$.<br><br><b>Solution:</b><br>$y - (-1) = \\frac{1}{2}(x - 6)$<br>$y + 1 = \\frac{1}{2}x - 3$<br>$y = \\frac{1}{2}x - 4$<br>Multiply by 2: $2y = x - 8$<br>$x - 2y = 8$<br><br><b>Worked Example 4</b> [4 marks — Extended]<br>Line $L$ passes through $A(-1, 5)$ and $B(3, -3)$. Find where $L$ crosses the $x$-axis.<br><br><b>Solution:</b><br>$m = \\frac{-3 - 5}{3 - (-1)} = \\frac{-8}{4} = -2$<br>$y - 5 = -2(x + 1)$<br>$y = -2x + 3$<br>At the $x$-axis, $y = 0$: $0 = -2x + 3$, so $x = 1.5$.<br>The line crosses at $(1.5, 0)$.<br><br><b>Exam Tip:</b> To find the $x$-intercept, set $y = 0$. To find the $y$-intercept, set $x = 0$.","content_zh":"<b>经典例题 1</b> [3 分]<br>求过 $(2,1)$ 和 $(6,9)$ 的直线方程。<br><br><b>解答：</b>$m = 2$，$y - 1 = 2(x-2)$，$y = 2x - 3$<br><br><b>经典例题 2</b> [2 分]<br>一条直线斜率为 $-3$，过 $(0, 7)$。写出其方程。<br><br><b>解答：</b>过 $(0,7)$，故 $c = 7$。$y = -3x + 7$<br><br><b>经典例题 3</b> [3 分 — 进阶]<br>求斜率为 $\\frac{1}{2}$、过 $(6, -1)$ 的直线方程，用 $ax + by = c$ 的形式表示。<br><br><b>解答：</b><br>$y + 1 = \\frac{1}{2}(x - 6)$，$y = \\frac{1}{2}x - 4$<br>两边乘 2：$x - 2y = 8$<br><br><b>经典例题 4</b> [4 分 — 进阶]<br>直线 $L$ 过 $A(-1, 5)$ 和 $B(3, -3)$。求 $L$ 与 $x$ 轴的交点。<br><br><b>解答：</b><br>$m = -2$，$y = -2x + 3$。令 $y = 0$：$x = 1.5$。交于 $(1.5, 0)$。<br><br><b>考试技巧：</b>求 $x$ 轴截距时令 $y = 0$；求 $y$ 轴截距时令 $x = 0$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.6', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Parallel lines</b> have the SAME gradient.<br>• If $L_1$ has gradient $m$, any line parallel to it also has gradient $m$.<br>• To find a parallel line through a given point: use $y - y_1 = m(x - x_1)$ with the same $m$.<br><br><b>Exam Tip</b><br>When asked \"find the equation of the line parallel to $y = 3x + 1$ through $(2, 5)$\", the gradient is 3.","content_zh":"<b>知识回顾</b><br>• <b>平行线</b>具有相同的斜率。<br>• 如果 $L_1$ 的斜率为 $m$，则任何与其平行的直线斜率也为 $m$。<br>• 求过已知点的平行线：使用相同的 $m$ 并代入 $y - y_1 = m(x - x_1)$。<br><br><b>考试技巧</b><br>当题目要求\"求过点 $(2, 5)$ 且平行于 $y = 3x + 1$ 的直线方程\"时，斜率为 3。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.6', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Find the equation of the line parallel to $y = -2x + 5$ that passes through $(3, 1)$.<br><br><b>Solution:</b><br>Gradient $m = -2$ (same as the given line).<br>$y - 1 = -2(x - 3)$<br>$y = -2x + 7$<br><br><b>Worked Example 2</b> [2 marks]<br>Are the lines $y = 3x - 1$ and $6x - 2y = 10$ parallel? Explain.<br><br><b>Solution:</b><br>Rearrange: $6x - 2y = 10 \\Rightarrow 2y = 6x - 10 \\Rightarrow y = 3x - 5$.<br>Both lines have gradient 3, so they are parallel. ✓<br><br><b>Worked Example 3</b> [3 marks — Extended]<br>Line $L_1$ has equation $2x + 3y = 12$. Line $L_2$ is parallel to $L_1$ and passes through $(6, 1)$. Find the equation of $L_2$.<br><br><b>Solution:</b><br>$L_1$: $3y = -2x + 12$, so $y = -\\frac{2}{3}x + 4$. Gradient $= -\\frac{2}{3}$.<br>$L_2$: $y - 1 = -\\frac{2}{3}(x - 6) = -\\frac{2}{3}x + 4$<br>$y = -\\frac{2}{3}x + 5$<br><br><b>Exam Tip:</b> \"Parallel\" means same gradient. Always rearrange to $y = mx + c$ first to identify the gradient.","content_zh":"<b>经典例题 1</b> [2 分]<br>求平行于 $y = -2x+5$、过 $(3,1)$ 的直线方程。<br><br><b>解答：</b>$m = -2$，$y - 1 = -2(x-3)$，$y = -2x + 7$<br><br><b>经典例题 2</b> [2 分]<br>$y = 3x - 1$ 和 $6x - 2y = 10$ 是否平行？请说明。<br><br><b>解答：</b><br>化简：$6x - 2y = 10 \\Rightarrow y = 3x - 5$。<br>两条直线斜率都是 3，所以它们平行。✓<br><br><b>经典例题 3</b> [3 分 — 进阶]<br>直线 $L_1$：$2x + 3y = 12$。$L_2$ 平行于 $L_1$ 且过 $(6, 1)$。求 $L_2$ 的方程。<br><br><b>解答：</b><br>$L_1$：$y = -\\frac{2}{3}x + 4$，斜率 $= -\\frac{2}{3}$。<br>$L_2$：$y - 1 = -\\frac{2}{3}(x - 6)$，$y = -\\frac{2}{3}x + 5$<br><br><b>考试技巧：</b>\"平行\"意味着斜率相同。先化为 $y = mx + c$ 形式以确定斜率。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.7', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Perpendicular lines</b> meet at 90°.<br>• If one line has gradient $m$, a perpendicular line has gradient $-\\frac{1}{m}$.<br>• Product of gradients of perpendicular lines = $-1$: $m_1 \\times m_2 = -1$.<br><br><b>Key Skills</b><br>• Find the gradient of a perpendicular line.<br>• Write the equation of a perpendicular through a given point.<br>• Find the perpendicular bisector of a line segment (passes through midpoint, perpendicular gradient).<br><br><b>Watch Out!</b><br>The negative reciprocal of $\\frac{2}{3}$ is $-\\frac{3}{2}$, not $-\\frac{2}{3}$.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• <b>垂直线</b>相交成 90°。<br>• 如果一条直线的斜率为 $m$，则其垂直线的斜率为 $-\\frac{1}{m}$。<br>• 垂直线斜率之积 = $-1$：$m_1 \\times m_2 = -1$。<br><br><b>关键技能</b><br>• 求垂直线的斜率。<br>• 写出通过给定点的垂直线方程。<br>• 求线段的垂直平分线（通过中点，具有垂直斜率）。<br><br><b>注意！</b><br>$\\frac{2}{3}$ 的负倒数是 $-\\frac{3}{2}$，而不是 $-\\frac{2}{3}$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.7', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Find the gradient of the line perpendicular to $y = \\frac{2}{5}x + 1$.<br><br><b>Solution:</b><br>Gradient of given line $= \\frac{2}{5}$.<br>Perpendicular gradient $= -\\frac{5}{2}$ (negative reciprocal).<br><br><b>Worked Example 2</b> [3 marks]<br>Find the equation of the line perpendicular to $y = 3x - 4$ that passes through $(6, 1)$.<br><br><b>Solution:</b><br>Perpendicular gradient $= -\\frac{1}{3}$.<br>$y - 1 = -\\frac{1}{3}(x - 6)$<br>$y = -\\frac{1}{3}x + 3$<br><br><b>Worked Example 3</b> [4 marks — Extended]<br>Line $L$ passes through $A(1, 4)$ and $B(5, 2)$. Find the equation of the perpendicular bisector of $AB$.<br><br><b>Solution:</b><br>Midpoint: $M = \\left(\\frac{1+5}{2}, \\frac{4+2}{2}\\right) = (3, 3)$<br>Gradient of $AB$: $m = \\frac{2-4}{5-1} = -\\frac{1}{2}$<br>Perpendicular gradient: $m_{\\perp} = 2$<br>$y - 3 = 2(x - 3)$<br>$y = 2x - 3$<br><br><b>Worked Example 4</b> [5 marks — Extended]<br>Show that the lines $y = 2x + 1$ and $x + 2y = 10$ are perpendicular, and find their point of intersection.<br><br><b>Solution:</b><br>Line 1 gradient: $m_1 = 2$<br>Line 2: $2y = -x + 10$, $y = -\\frac{1}{2}x + 5$, so $m_2 = -\\frac{1}{2}$.<br>$m_1 \\times m_2 = 2 \\times (-\\frac{1}{2}) = -1$ ✓ Perpendicular.<br><br>Intersection: $2x + 1 = -\\frac{1}{2}x + 5$<br>$\\frac{5}{2}x = 4$, $x = \\frac{8}{5}$<br>$y = 2(\\frac{8}{5}) + 1 = \\frac{21}{5}$<br>Intersection: $\\left(\\frac{8}{5}, \\frac{21}{5}\\right)$<br><br><b>Exam Tip:</b> To prove lines are perpendicular, show that the product of their gradients equals $-1$.","content_zh":"<b>经典例题 1</b> [3 分]<br>求垂直于 $y = \\frac{2}{5}x + 1$ 的直线的斜率。<br><br><b>解答：</b><br>已知直线斜率 $= \\frac{2}{5}$。垂直线斜率 $= -\\frac{5}{2}$（负倒数）。<br><br><b>经典例题 2</b> [3 分]<br>求垂直于 $y = 3x - 4$ 且过 $(6, 1)$ 的直线方程。<br><br><b>解答：</b><br>垂直斜率 $= -\\frac{1}{3}$。$y - 1 = -\\frac{1}{3}(x - 6)$，$y = -\\frac{1}{3}x + 3$<br><br><b>经典例题 3</b> [4 分 — 进阶]<br>直线 $L$ 通过 $A(1, 4)$ 和 $B(5, 2)$。求 $AB$ 的垂直平分线方程。<br><br><b>解答：</b><br>中点 $M = (3, 3)$，$AB$ 斜率 $= -\\frac{1}{2}$，垂直斜率 $= 2$。<br>$y - 3 = 2(x - 3)$，$y = 2x - 3$<br><br><b>经典例题 4</b> [5 分 — 进阶]<br>证明 $y = 2x + 1$ 和 $x + 2y = 10$ 垂直，并求其交点。<br><br><b>解答：</b><br>$m_1 = 2$，$m_2 = -\\frac{1}{2}$。$m_1 \\times m_2 = -1$ ✓ 垂直。<br>联立：$2x + 1 = -\\frac{1}{2}x + 5$，$x = \\frac{8}{5}$，$y = \\frac{21}{5}$。<br>交于 $\\left(\\frac{8}{5}, \\frac{21}{5}\\right)$<br><br><b>考试技巧：</b>证明两线垂直时，证明斜率之积等于 $-1$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.1', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>sequence</b> is an ordered list of numbers following a pattern.<br>• <b>Term-to-term rule</b>: how to get from one term to the next.<br>• <b>$n$th term</b> (position-to-term): $T_n$ gives any term directly.<br>• <b>Arithmetic</b>: constant difference $d$. $T_n = a + (n-1)d$ or $T_n = dn + (a - d)$.<br><br><b>Higher Only</b><br>• <b>Quadratic sequences</b>: second differences are constant. $T_n = an^2 + bn + c$.<br>• <b>Geometric sequences</b>: constant ratio $r$. $T_n = ar^{n-1}$.<br>• <b>Fibonacci-type</b>: each term = sum of previous two.<br><br><b>Exam Tip</b><br>Always check your formula with $n = 1, 2, 3$.","content_zh":"<b>知识回顾</b><br>• <b>数列</b>是按某种规律排列的一组数字。<br>• <b>逐项规则</b>：如何从一项得到下一项。<br>• <b>第 $n$ 项</b>（通项）：$T_n$ 可直接给出任意项。<br>• <b>等差数列</b>：公差 $d$ 为常数。$T_n = a + (n-1)d$ 或 $T_n = dn + (a - d)$。<br><br><b>仅 Higher</b><br>• <b>二阶等差数列</b>：二阶差分为常数。$T_n = an^2 + bn + c$。<br>• <b>等比数列</b>：公比 $r$ 为常数。$T_n = ar^{n-1}$。<br>• <b>斐波那契型</b>：每一项等于前两项之和。<br><br><b>考试技巧</b><br>务必用 $n = 1, 2, 3$ 来检查你的公式。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Find the $n$th term of $7, 11, 15, 19, ...$<br><br><b>Solution:</b><br>$d = 4$, $T_n = 4n + 3$. Check: $T_1 = 7$ ✓<br><br><b>Worked Example 2</b> (Higher) [4 marks]<br>Find the $n$th term of $2, 8, 18, 32, 50, ...$<br><br><b>Solution:</b><br>1st diff: $6, 10, 14, 18$. 2nd diff: $4, 4, 4$ → $a = 2$.<br>$T_n = 2n^2 + bn + c$.<br>$n = 1$: $2 + b + c = 2$ → $b + c = 0$.<br>$n = 2$: $8 + 2b + c = 8$ → $2b + c = 0$.<br>$b = 0, c = 0$. $T_n = 2n^2$.","content_zh":"<b>经典例题 1</b> [2 分]<br>求 $7, 11, 15, 19, ...$ 的通项。<br><br><b>解答：</b>$d = 4$，$T_n = 4n + 3$<br><br><b>经典例题 2</b>（Higher）[4 分]<br>求 $2, 8, 18, 32, 50, ...$ 的通项。<br><br><b>解答：</b>二阶差 = 4，$a = 2$，解得 $T_n = 2n^2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.2', 'knowledge', '{"content":"<b>Higher Only</b><br><br><b>Recap</b><br>• <b>Function notation</b>: $f(x) = 2x + 3$ means \"the function $f$ maps $x$ to $2x + 3$\".<br>• $f(5) = 2(5) + 3 = 13$.<br>• <b>Composite functions</b>: $fg(x) = f(g(x))$. Do $g$ first, then $f$.<br>• <b>Inverse functions</b>: $f^{-1}(x)$ undoes $f$. Swap $x$ and $y$, then rearrange.<br>• $ff^{-1}(x) = f^{-1}f(x) = x$.<br>• The graph of $f^{-1}$ is the reflection of $f$ in $y = x$.<br><br><b>Watch Out!</b><br>$fg(x) \\neq gf(x)$ — composition is NOT commutative.","content_zh":"<b>仅 Higher</b><br><br><b>知识回顾</b><br>• 函数符号：$f(x) = 2x + 3$。<br>• 复合函数：$fg(x) = f(g(x))$，先 $g$ 后 $f$。<br>• 反函数：$f^{-1}(x)$，交换 $x, y$ 后解出。<br>• $f^{-1}$ 图像是 $f$ 关于 $y = x$ 的对称。<br><br><b>注意！</b>$fg(x) \\neq gf(x)$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.2', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>$f(x) = 3x - 1$, $g(x) = x^2 + 4$.<br>(a) Find $gf(2)$. (b) Find $fg(x)$. (c) Find $f^{-1}(x)$.<br><br><b>Solution:</b><br>(a) $f(2) = 5$, $g(5) = 29$. So $gf(2) = 29$.<br>(b) $fg(x) = f(x^2 + 4) = 3(x^2 + 4) - 1 = 3x^2 + 11$.<br>(c) $y = 3x - 1$ → $x = 3y - 1$ → $y = \\frac{x + 1}{3}$.<br>$f^{-1}(x) = \\frac{x + 1}{3}$.","content_zh":"<b>经典例题</b> [5 分]<br>$f(x) = 3x-1$, $g(x) = x^2+4$。<br>(a) $gf(2)$ (b) $fg(x)$ (c) $f^{-1}(x)$<br><br><b>解答：</b>(a) $f(2)=5, g(5)=29$<br>(b) $3x^2 + 11$<br>(c) $f^{-1}(x) = \\frac{x+1}{3}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Linear</b>: $y = mx + c$. Straight line.<br>• <b>Quadratic</b>: $y = ax^2 + bx + c$. Parabola.<br>• <b>Cubic</b>: $y = ax^3 + ...$. S-shaped.<br>• <b>Reciprocal</b>: $y = \\frac{a}{x}$. Hyperbola with asymptotes along axes.<br><br><b>Key Skills</b><br>• Plot graphs from tables of values.<br>• Find solutions graphically (intersections with $x$-axis or other curves).<br>• Read off and interpret gradients, intercepts, and turning points.<br><br><b>Higher Only</b><br>• <b>Exponential</b>: $y = a^x$ (growth), $y = a^{-x}$ (decay).<br>• <b>Trig graphs</b>: $\\sin x$, $\\cos x$, $\\tan x$ with period and amplitude.<br>• <b>Transformations</b>: $f(x) + a$ (up), $f(x + a)$ (left), $af(x)$ (vertical stretch), $f(ax)$ (horizontal compress).<br>• <b>Tangent to a curve</b>: draw tangent, calculate gradient.","content_zh":"<b>知识回顾</b><br>• <b>线性</b>：$y = mx + c$。直线。<br>• <b>二次</b>：$y = ax^2 + bx + c$。抛物线。<br>• <b>三次</b>：$y = ax^3 + ...$。S 形曲线。<br>• <b>反比例</b>：$y = \\frac{a}{x}$。渐近线沿坐标轴的双曲线。<br><br><b>关键技能</b><br>• 根据数值表绘制图表。<br>• 利用图表寻找解（与 $x$ 轴或其他曲线的交点）。<br>• 读取并解释斜率、截距和拐点。<br><br><b>仅 Higher</b><br>• <b>指数</b>：$y = a^x$（增长），$y = a^{-x}$（衰减）。<br>• <b>三角函数图表</b>：带有周期和振幅的 $\\sin x$，$\\cos x$，$\\tan x$。<br>• <b>变换</b>：$f(x) + a$（向上），$f(x + a)$（向左），$af(x)$（垂直拉伸），$f(ax)$（水平压缩）。<br>• <b>曲线的切线</b>：绘制切线，计算斜率。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.3', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>The graph of $y = f(x)$ has a maximum at $(2, 5)$. Write down the coordinates of the maximum of:<br>(a) $y = f(x) + 3$ &nbsp;&nbsp; (b) $y = f(x - 4)$ &nbsp;&nbsp; (c) $y = -f(x)$<br><br><b>Solution:</b><br>(a) Shift up 3: $(2, 8)$<br>(b) Shift right 4: $(6, 5)$<br>(c) Reflect in $x$-axis: $(2, -5)$ — this becomes a <b>minimum</b>.<br><br><b>Exam Tip:</b> $f(x - a)$ shifts RIGHT, $f(x + a)$ shifts LEFT. The sign is opposite to what you might expect.","content_zh":"<b>经典例题</b> [4 分]<br>$y = f(x)$ 的图像在 $(2, 5)$ 处有一个极大值点。写出以下函数极大值点的坐标：<br>(a) $y = f(x) + 3$ &nbsp;&nbsp; (b) $y = f(x - 4)$ &nbsp;&nbsp; (c) $y = -f(x)$<br><br><b>解答：</b><br>(a) 向上平移 3 个单位：$(2, 8)$<br>(b) 向右平移 4 个单位：$(6, 5)$<br>(c) 关于 $x$ 轴翻折：$(2, -5)$ —— 这会变成一个<b>极小值点</b>。<br><br><b>考试技巧：</b>$f(x - a)$ 向右平移，$f(x + a)$ 向左平移。符号与你预期的相反。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.4', 'knowledge', '{"content":"<b>Higher Only</b><br><br><b>Recap</b><br>• <b>Differentiation</b>: if $y = ax^n$, then $\\frac{dy}{dx} = anx^{n-1}$.<br>• $\\frac{dy}{dx}$ gives the <b>gradient of the curve</b> at any point.<br>• <b>Turning points</b>: set $\\frac{dy}{dx} = 0$.<br>• Nature: $\\frac{d^2y}{dx^2} > 0$ → min; $\\frac{d^2y}{dx^2} < 0$ → max.<br><br><b>Key Skills</b><br>• Differentiate polynomials.<br>• Find and classify turning points.<br>• Find the equation of a tangent at a given point.<br><br><b>Exam Tip</b><br>For tangent equation: find $\\frac{dy}{dx}$ at the point (= gradient $m$), then use $y - y_1 = m(x - x_1)$.","content_zh":"<b>仅 Higher</b><br><br><b>知识回顾</b><br>• <b>求导</b>：如果 $y = ax^n$，那么 $\\frac{dy}{dx} = anx^{n-1}$。<br>• $\\frac{dy}{dx}$ 给出了曲线在任意点处的<b>斜率</b>。<br>• <b>拐点</b>：令 $\\frac{dy}{dx} = 0$。<br>• 性质：$\\frac{d^2y}{dx^2} > 0$ → 极小值；$\\frac{d^2y}{dx^2} < 0$ → 极大值。<br><br><b>关键技能</b><br>• 多项式求导。<br>• 寻找并分类拐点。<br>• 在给定点处求切线方程。<br><br><b>考试技巧</b><br>对于切线方程：求出该点处的 $\\frac{dy}{dx}$（即斜率 $m$），然后使用 $y - y_1 = m(x - x_1)$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.4', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>$y = x^3 - 6x^2 + 9x + 2$. Find the turning points and determine their nature.<br><br><b>Solution:</b><br>$\\frac{dy}{dx} = 3x^2 - 12x + 9 = 3(x^2 - 4x + 3) = 3(x-1)(x-3)$<br>Set $= 0$: $x = 1$ or $x = 3$.<br><br>$\\frac{d^2y}{dx^2} = 6x - 12$<br>At $x = 1$: $6 - 12 = -6 < 0$ → <b>maximum</b>. $y = 1 - 6 + 9 + 2 = 6$.<br>At $x = 3$: $18 - 12 = 6 > 0$ → <b>minimum</b>. $y = 27 - 54 + 27 + 2 = 2$.<br><br>Max $(1, 6)$, Min $(3, 2)$.","content_zh":"<b>经典例题</b> [5 分]<br>$y = x^3 - 6x^2 + 9x + 2$。找到拐点并确定其性质。<br><br><b>解答：</b><br>$\\frac{dy}{dx} = 3x^2 - 12x + 9 = 3(x^2 - 4x + 3) = 3(x-1)(x-3)$<br>令其 $= 0$：$x = 1$ 或 $x = 3$。<br><br>$\\frac{d^2y}{dx^2} = 6x - 12$<br>当 $x = 1$ 时：$6 - 12 = -6 < 0$ → <b>极大值</b>。$y = 1 - 6 + 9 + 2 = 6$。<br>当 $x = 3$ 时：$18 - 12 = 6 > 0$ → <b>极小值</b>。$y = 27 - 54 + 27 + 2 = 2$。<br><br>极大值点 $(1, 6)$，极小值点 $(3, 2)$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
